INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (1, 'Invoice Generator', 'invoice-generator', 'Create a professional invoice online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional invoice online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-cash-coin', 'free', '{"fields":[{"name":"invoice_number","label":"Invoice Number","type":"text","required":true},{"name":"invoice_date","label":"Invoice Date","type":"date","required":true},{"name":"due_date","label":"Due Date","type":"date","required":false},{"name":"from_name","label":"From (Your Business)","type":"textarea","required":true},{"name":"to_name","label":"Bill To","type":"textarea","required":true},{"name":"items","label":"Line Items","type":"line_items","required":true},{"name":"tax_rate","label":"Tax Rate (%)","type":"number","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false}]}', '[{"q":"Is the Invoice Generator free to use?","a":"Yes, every Invoxaco plan includes access to the invoice tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the invoice as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Invoice Generator - Free Online Invoice Generator | Invoxaco', 'Generate a Invoice Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 1);
