INSERT INTO document_templates (category_id, name, slug, short_description, description, icon, plan_required, fields_schema, faqs, is_built, is_active, meta_title, meta_description, sort_order) VALUES (4, 'Offer Letter Generator', 'offer-letter-generator', 'Create a professional offer letter online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'Create a professional offer letter online in minutes — fill in the details, preview instantly, and download as PDF or DOCX.', 'bi-people', 'free', '{"fields":[{"name":"letter_date","label":"Letter Date","type":"date","required":true},{"name":"candidate_name","label":"Candidate Name","type":"text","required":true},{"name":"job_title","label":"Job Title","type":"text","required":true},{"name":"department","label":"Department","type":"text","required":false},{"name":"start_date","label":"Start Date","type":"date","required":true},{"name":"salary","label":"Annual Salary","type":"text","required":true},{"name":"reporting_manager","label":"Reporting Manager","type":"text","required":false},{"name":"additional_terms","label":"Additional Terms","type":"textarea","required":false}]}', '[{"q":"Is the Offer Letter Generator free to use?","a":"Yes, every Invoxaco plan includes access to the offer letter tool. Free plan documents are watermarked and limited to 10 per month; Pro and Premium plans remove the watermark and raise or remove the limit."},{"q":"Can I download the offer letter as PDF and Word?","a":"Yes. Every document you create can be exported as a print-ready PDF, and Pro/Premium plans can also export an editable DOCX file."},{"q":"Can I email the document directly to my client?","a":"Yes, Pro and Premium users can send any generated document as a PDF or DOCX email attachment directly from Invoxaco."}]', 1, 1, 'Offer Letter Generator - Free Online Offer Letter Generator | Invoxaco', 'Generate a Offer Letter Generator online free with Invoxaco. Fill a simple form, preview instantly, and export as PDF or Word. No design skills needed.', 1);
